UPDATE INV.CONCIERGE_AMENITY_REQ
   SET PROC_STAT_CD = #{procStatCd}, MOD_USER = #{modUser}, MOD_DT = NOW()
 WHERE REQ_NO = #{reqNo}

UPDATE INV.CONCIERGE_PARKING
   SET PMS_SYNC_YN = #{pmsSyncYn}, MOD_USER = #{modUser}, MOD_DT = NOW()
 WHERE REQ_NO = #{reqNo}

UPDATE INV.CONCIERGE_LATE_CO
   SET PROC_STAT_CD = #{procStatCd}, MOD_USER = #{modUser}, MOD_DT = NOW()
 WHERE REQ_NO = #{reqNo}

UPDATE INV.CCS_DEPARTMENT
SET DEPT_NM = #{deptNm}, SORT_ORD = #{sortOrd}, USE_YN = #{useYn}, MOD_USER = 'ADMIN', MOD_DT = NOW()
WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd} AND DEPT_CD = #{deptCd}

mapper.select:
SELECT TASK_ID AS taskId, PROP_CD AS propCd, CMPX_CD AS cmpxCd,
       DEPT_CD AS deptCd, SOURCE_TYPE AS sourceType, SOURCE_REF_NO AS sourceRefNo,
       TITLE AS title, MEMO AS memo, RM_NO AS rmNo,
       ASSIGNEE_ID AS assigneeId, STATUS_CD AS statusCd,
       CREATED_AT AS createdAt, UPDATED_AT AS updatedAt
  FROM INV.CCS_TASK
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}

   AND DEPT_CD = #{deptCd}


   AND STATUS_CD = #{statusCd}

 ORDER BY CREATED_AT DESC

SELECT COUNT(*) AS totalCnt, SUM(CASE WHEN STATUS_CD = 'DONE' THEN 1 ELSE 0 END) AS doneCnt, AVG(CASE WHEN STATUS_CD = 'DONE' THEN TIMESTAMPDIFF(MINUTE, CREATED_AT, UPDATED_AT) END) AS avgMinutes FROM INV.CCS_TASK WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND DEPT_CD = #{deptCd}
AND DATE(CREATED_AT) = CURDATE()

SELECT LF_ID AS lfId, PROP_CD AS propCd, CMPX_CD AS cmpxCd,
       REPORTER_TYPE AS reporterType, REPORTER_REF AS reporterRef,
       RM_NO AS rmNo, CATEGORY AS category, ITEM_NAME AS itemName,
       DESCRIPTION AS description, LOCATION_HINT AS locationHint,
       FOUND_AT AS foundAt, MATCHED_LF_ID AS matchedLfId,
       STATUS_CD AS statusCd, HANDLER_ID AS handlerId, NOTE AS note,
       CREATED_AT AS createdAt, UPDATED_AT AS updatedAt
  FROM INV.CCS_LOSTFOUND
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND STATUS_CD = #{statusCd}
AND CATEGORY = #{category}
AND REPORTER_TYPE = #{reporterType}
 ORDER BY CREATED_AT DESC

SELECT VOC_ID AS vocId, PROP_CD AS propCd, CMPX_CD AS cmpxCd,
       RSV_NO AS rsvNo, RM_NO AS rmNo,
       CATEGORY AS category, SEVERITY AS severity,
       TITLE AS title, CONTENT AS content,
       STATUS_CD AS statusCd, HANDLER_ID AS handlerId,
       RESOLUTION AS resolution, SATISFACTION AS satisfaction,
       CREATED_AT AS createdAt, UPDATED_AT AS updatedAt, RESOLVED_AT AS resolvedAt
  FROM INV.CCS_VOC
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND STATUS_CD = #{statusCd}
AND CATEGORY = #{category}
AND SEVERITY = #{severity}
 ORDER BY CREATED_AT DESC

