UPDATE INV.CCS_RENTAL_ITEM
   SET NAME = #{name}, DESCRIPTION = #{description}, CATEGORY = #{category},
       STOCK_TOTAL = #{stockTotal}, USE_YN = #{useYn}
 WHERE ITEM_ID = #{itemId}

UPDATE INV.CCS_RENTAL_ITEM
   SET STOCK_AVAILABLE = STOCK_AVAILABLE + #{delta}
 WHERE ITEM_ID = #{itemId}

mapper.select:
SELECT ORDER_ID AS orderId, PROP_CD AS propCd, CMPX_CD AS cmpxCd,
       RSV_NO AS rsvNo, ITEM_ID AS itemId, QTY AS qty,
       STATUS_CD AS statusCd, REQUESTED_AT AS requestedAt,
       LOANED_AT AS loanedAt, DUE_AT AS dueAt, RETURNED_AT AS returnedAt,
       HANDLER_ID AS handlerId, NOTE AS note
  FROM INV.CCS_RENTAL_ORDER
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND STATUS_CD = #{statusCd}
AND RSV_NO = #{rsvNo}
 ORDER BY REQUESTED_AT DESC

SELECT AUDIT_ID AS auditId, PROP_CD AS propCd, CMPX_CD AS cmpxCd,
       ACTOR_ID AS actorId, ACTOR_TYPE AS actorType,
       ACTION AS action, DOMAIN AS domain, ENTITY_ID AS entityId,
       BEFORE_JSON AS beforeJson, AFTER_JSON AS afterJson,
       CREATED_AT AS createdAt
  FROM INV.CCS_AUDIT_LOG
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND DOMAIN = #{domain}
AND ACTION = #{action}
AND ACTOR_ID = #{actorId}
AND CREATED_AT >= #{fromDt}
AND CREATED_AT <= #{toDt}
 ORDER BY CREATED_AT DESC
 LIMIT 500

SELECT DEPT_CD AS deptCd, SOURCE_TYPE AS sourceType,
       COUNT(*) AS totalCount,
       SUM(CASE WHEN STATUS_CD = 'DONE' THEN 1 ELSE 0 END) AS doneCount,
       AVG(CASE WHEN STATUS_CD = 'DONE' THEN TIMESTAMPDIFF(MINUTE, CREATED_AT, UPDATED_AT) END) AS avgElapsedMin,
       MAX(CASE WHEN STATUS_CD = 'DONE' THEN TIMESTAMPDIFF(MINUTE, CREATED_AT, UPDATED_AT) END) AS maxElapsedMin
  FROM INV.CCS_TASK
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND CREATED_AT >= #{fromDt}
AND CREATED_AT <= #{toDt}
 GROUP BY DEPT_CD, SOURCE_TYPE

SELECT DAYOFWEEK(CREATED_AT) AS dow,
       HOUR(CREATED_AT) AS hour,
       COUNT(*) AS cnt
  FROM INV.CCS_TASK
 WHERE PROP_CD = #{propCd} AND CMPX_CD = #{cmpxCd}
AND CREATED_AT >= #{fromDt}
AND CREATED_AT <= #{toDt}
 GROUP BY DAYOFWEEK(CREATED_AT), HOUR(CREATED_AT)
 ORDER BY dow, hour
